INSERT INTO preguntas VALUES (258, NULL, '¿Qué es una expresión algebraica (E.A.)?', 'Una expresión algebraica es una combinación de variables y constantes donde se realizan operaciones aritméticas de forma finita, sin exponentes en las variables.', NULL, 1, TRUE, NULL, 77, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (30, NULL, '... El hombre no puede percibir lo realidad de las cosas, lo que el hombre ve o siente no es más que el reflejo imperfecto de una realidad espiritual, que le es posible alcanzar por medio de la razón, y a esa realidad la llama "idea" o "forma". La idea más perfecta es Dios, que es el origen y el fin de todas las cosas. El hombre posee un alma inmortal que la muerte libera de su envoltura corpórea, y después de sucesivas encarnaciones, el alma se reintegra a Dios que es el bien. Durante la vida, la felicidad del hombre tiene por base la virtud; y la sociedad organizada, que es el Estado, tiene por fin la justicia y como medio la educación"... (PLATÓN).
INSERT INTO preguntas VALUES (37, NULL, 'La religión pertenece al aspecto racional de la naturaleza humana, porque ofrece, o intenta ofrecer, una respuesta a las eternas cuestiones que la vida misma plantea a todo ser humano, salvaje o civilizado. En primer lugar, el hombre vislumbrai, aunque en forma oscura, que no puede dar razón de su ser, ni se basta a sí mismo; tiene un sentimiento de ser criatura o de dependencia, del misterio del todo, de su propia insignificancia. En segundo lugar, el hombre se percata de la vida sensorial y de la naturaleza que lo envuelve con sus inmensos y tremendos poderes, con su orden cíclico y sus desastres imprevistos y abrumadores. En tercer lugar, sabe que la muerte le espera tarde o temprano.', 'En el texto nos hablan sobre las eternas cuestiones que la vida plantea, ahora bien, para hallar el tema debemos hacer la pregunta básica: ¿de qué me habla el texto? La respuesta inmediata es: las interrogantes o cuestionamientos sobre la existencia', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
