INSERT INTO preguntas VALUES (82, NULL, 'Contiene un adjetivo indefinido.', 'Los adjetivos indefinidos son aquellos adjetivos que no describen al sustantivo pero especifican su alcance, con la particularidad de que no lo hacen en forma precisa, sino apenas aproximada. Por ejemplo: Cierto día conocí Europa.
INSERT INTO preguntas VALUES (88, NULL, 'Muy reconocido en Chiclayo por su popular columna periodística ''A propósito'' en un diario local donde hacía gala de sus estampas costumbristas y anecdóticas', 'Nacido el 16 de setiembre de 1902 en San José de Bellavista, distrito de la provincia de Pacasmayo, “Nixa” llegó a Chiclayo en 1918. Fue cofundador del diario La Industria de Chiclayo, en 1952. Desde entonces, también, escribió su famosa columna “A propósito”, compuesta por narraciones breves de un solo capítulo, un tema vinculado con la historia y la tradición de los pueblos norteños del Perú. Fue, también, colaborador del suplemento Lundero del diario La Industria, de Trujillo.
INSERT INTO preguntas VALUES (96, NULL, 'El problema principal que tuvieron que afrontar los militares incas en su lucha contra el invasor español fue:', 'D. Correcta. Uno de los problemas más graves que enfrentaron los incas fue el apoyo de los curacas (jefes locales de etnias y comunidades sometidas por los incas) a los españoles. Muchas de estas comunidades, que habían sido conquistadas o dominadas por los incas, vieron en los españoles una oportunidad para liberarse del control incaico. Este factor de división interna fue clave para el éxito de la conquista española. Los españoles aprovecharon estas alianzas para obtener tropas adicionales, información y suministros, debilitando así la resistencia inca desde dentro.', NULL, 2, TRUE, NULL, 83, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (104, NULL, 'Tipo de crédito por el cual el banco autoriza a su cliente girar cheques por un monto superior a sus depósitos en cuenta corriente:', 'A. Correcto. Avance de cuenta corriente. Este tipo de crédito, también conocido como crédito en cuenta corriente o sobregiro bancario, permite a los clientes de un banco girar cheques o hacer pagos por un monto superior al saldo que tienen en su cuenta corriente. El banco otorga un límite adicional de crédito, y el cliente debe devolver el dinero con intereses según los términos acordados.', NULL, 2, TRUE, NULL, 85, NULL, 'aprobado', NULL);
