INSERT INTO preguntas VALUES (267, NULL, 'El metano, CH4, es el principal componente del combustible de gas natural. Su molécula tiene una geometría tetraédrica y como sus cuatro enlaces son iguales resultan ser apolares. El tetracloruro de carbono, CCl4, es un solvente de geometría molécula semejante al metano. En cuál de las alternativas el tetracloruro de carbono es soluble con:', 'd. Correcta
INSERT INTO preguntas VALUES (33, NULL, 'Cantidad de palabras con acento enfático en el texto: ''Quisiera saber por qué no llegó a la reunión y cómo lo ubicaremos. Dónde estará''', 'El acento enfático es el que se usa con las palabras: qué, quién, quiénes, cuál, cuáles, cúyo, cúyos, cúya, cúyas, cuánto, cuántos, cuánta, cuántas, cómo, cuándo, dónde, cuán, cuando queremos expresar admiración, pregunta o duda. QUE (conjunción y pronombre relativo) Sus formas del relativo son: el que, la que, lo que.', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (40, NULL, 'La oración correcta, con uso de tildación diacrítica es', 'La lista de monosílabos con tilde diacrítica es la siguiente: 1. Tú (pronombre personal), frente a tu (adjetivo posesivo): «Tú tienes muy claro cómo planear tu futuro». 2. Él (pronombre personal), frente a el (artículo): «Él siempre elige el camino más corto». 3. Mí (pronombre personal), frente a mi (adjetivo posesivo o nota musical): «Para mí es importante que te acuerdes de que es mi cumpleaños». 4. Sí (pronombre personal, adverbio de afirmación o sustantivo), frente a si (conjunción o nota musical): «Sí, el otro día se me olvidó comprobar si había apagado la televisión». 5. Té (sustantivo ‘infusión’), frente a te (pronombre o letra te): «Por lo que veo, el té rojo es el que más te gusta». 6. Dé (forma del verbo dar), frente a de (preposición o letra de): «Me encanta que mi hijo me dé besos de esquimal». 7. Sé (forma del verbo ser o saber), frente a se (pronombre, indicador de impersonalidad o de marca refleja): «Sé muy bien que no se rinde a la primera de cambio». 8. Más (adverbio, adjetivo, pronombre, conjunción con valor de suma o sustantivo), frente a mas (conjunción adversativa equivalente a pero): «Hoy he trabajado más horas, mas me siento con energía»', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
