INSERT INTO preguntas VALUES (85, NULL, '''Al cielo le robé una estrella; al prado, una rosa tan bella''. El verso citado corresponde a una', 'Las figuras literarias, tropos o figuras retóricas, son una serie de giros del lenguaje que se emplean para embellecer el discurso, especialmente en el contexto de la oratoria y de la literatura, alterando significativamente el modo común y cotidiano de emplear el idioma.
INSERT INTO preguntas VALUES (93, NULL, 'Su finalidad es alcanzar el desarrollo equilibrado en el país, buscando la promoción permanente del hombre y la sociedad. Corresponde a:', 'C. Correcta. La Regionalización es un proceso mediante el cual se busca descentralizar el poder, transfiriendo competencias y recursos del gobierno central a los gobiernos regionales. Su finalidad es promover el desarrollo equilibrado del país, reduciendo las desigualdades entre las diferentes regiones. En este sentido, la regionalización es una estrategia que busca mejorar la gestión de los recursos y fomentar el desarrollo integral de las personas y las comunidades en todo el territorio nacional.', NULL, 2, TRUE, NULL, 82, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (98, NULL, 'Con relación a la guerra entre Perú, Chile y Bolivia desarrollada a fines del siglo XIX, es incorrecta:', 'A. Correcta. El capitalismo inglés triunfó, debido a que había decidido invertir en empresas chilenas, con el triunfo en la guerra aprovecharon los recursos del guano y del salitre.
