INSERT INTO preguntas VALUES (268, NULL, 'Líquido corporal contenido en el conducto del epéndimo', 'D. CORRECTA. El líquido cefalorraquídeo es producido por los ependimocitos que revisten los plexos coroideos en los ventrículos cerebrales; el líquido circula en los ventrículos, el conducto ependimario y el espacio subaracnoideo ubicado alrededor del encéfalo y la médula espinal.', NULL, 2, TRUE, NULL, 88, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (35, NULL, 'La cultura no existe por sí misma. Por tanto: No existe independientemente de la vida de los hombres. La cultura es lo generado en su vida de relación con la naturaleza y con ellos mismos, que forman su propia cultura: religión, filosofía, artes, supersticiones, modos de ignorancia, etc.', 'La comprensión es la aptitud o astucia para alcanzar un entendimiento de las cosas. Se conoce como «comprensión lectora» el desarrollo de significados mediante la adquisición de las ideas más importantes de un texto y la posibilidad de establecer vínculos entre estas y otras ideas adquiridas con anterioridad. Es posible comprender un texto de manera literal (centrándose en aquellos datos expuestos de forma explícita), crítica (con juicios fundamentados sobre los valores del texto) o inferencial (leyendo y comprendiendo entre líneas), etc.
