INSERT INTO preguntas VALUES (100, NULL, 'Es una franja que va paralela al desierto costero (oeste), limita por el norte con el bosque seco ecuatorial y por el este con la Puna. Esta ecorregión se denomina:', 'C. Correcta. serranía esteparia. Se extiende desde el departamento de la Libertad hasta el norte de Chile, en las vertientes occidentales andinas. Desde los 1000 hasta los 3800 m.s.n.m. predominan dos especies caducifolias: el mito y el huanarpo. En las laderas rocosas se encuentran varias especies de achupallas; así mismo encontramos la cabuya o pita. Entre los 2600 y los 3200 m.s.n.m, en lugares inaccesibles. En él destacan las siguientes especies: el higuerón, el aliso. Estos bosques también son conocidos como “bosques de arroyada” por crecer en las quebradas. Las formaciones de chochos: se ubican entre los 2900 - 3200 y los 3800 y los 4000 m.s.n.m. Predomina una leguminosa conocida como lupino o chocho.', NULL, 2, TRUE, NULL, 84, NULL, 'aprobado', NULL);
