INSERT INTO preguntas VALUES (28, NULL, 'Asimismo no se tilda, porque al formarse la palabra compuesta', 'Cuando una palabra que normalmente lleva tilde pasa a ser el primer elemento de una voz compuesta, pierde el acento ortográfico que como simple le correspondía: anuloplastia, valvuloplastia, valvulotomía o el adverbio modal Asimismo. Las palabras compuestas se forman uniendo dos elementos, que suelen ser sustantivos, adjetivos y verbos en los casos más frecuentes, pero también pueden ser adverbios o pronombres. Asimismo, escrito como una sola palabra, es un adverbio que indica igualdad, semejanza, conformidad o relación, es decir, es equivalente a también y además. La Real Academia Española (RAE) también acepta la grafía en dos palabras, la locución adverbial así mismo, cuando tiene ese valor.', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (29, NULL, 'Sustituya las palabras en paréntesis por los antónimos respectivos: No solo pretendieron (denigrar) su imagen, sino que buscaban (ensañarse) con su desgracia', 'Los antónimos contextuales son aquellos términos que al reemplazar a otro en un contexto oracional expresan proposiciones o enunciados que contradicen al mensaje original.
