INSERT INTO preguntas VALUES (89, NULL, 'El objeto de estudio del psicoanálisis es:', 'A. Correcta. el inconsciente. En psicoanálisis, el inconsciente es el concepto clave de la teoría, puesto que constituye su principal objeto de estudio, y designa en el sentido tópico un sistema y un lugar psíquico desconocido para la conciencia en el sentido dinámico al conjunto de los contenidos reprimidos que son mantenidos al margen, apartados de la conciencia, aun cuando ellos muestren una permanente efectividad psíquica e intensa actividad a través de mecanismos y formaciones específicas.', NULL, 2, TRUE, NULL, 81, NULL, 'aprobado', NULL);
