INSERT INTO preguntas VALUES (238, NULL, 'Expresión que exprese sonido cacofónico', 'Vicios del Lenguaje', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (239, NULL, 'El profesor dice que las oraciones incompletas son ejercicios absurdos. Frente al caso, ¿Qué se puede recomendar?', 'Comprensión Lectora', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (240, NULL, 'El editorial es un texto', 'Sinonimia por Significado', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (241, NULL, 'Una de las oraciones es excluyente con respecto a la democracia: I. la democracia requiere que sus instituciones funcionen correctamente. II. requiere un poder legislativo que represente al pueblo. III. exige un poder judicial independiente. IV. no requiere partidos políticos y sistemas electorales de manera apropiada. V. requiere fuerzas de seguridad profesionales.', 'Texto Excluido', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (242, NULL, 'En atención al uso de la tilde, ¿qué sucede con el aprendizaje de Ricardo respecto a qué, cómo, dónde, cuándo?', 'Comprensión Lectora', NULL, 2, TRUE, NULL, 73, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (243, NULL, 'Jessica ve su reloj y nota que está atrasado 6 minutos, pero recuerda que hace 3 horas marcaba la hora exacta. Pasado un tiempo responde con la hora correcta: 14:18, pero su reloj marcaba 14:00. ¿Qué hora era cuando Jessica notó que su reloj estaba atrasado 6 minutos?', 'Cronometría', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (244, NULL, 'Nancy desea plantar árboles en el patio de su casa. ¿Cuántos árboles como mínimo podrá plantar en 8 filas, si cada fila debe tener solo 3 árboles?', 'Razonamiento Geométrico', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (245, NULL, 'Se desea determinar el costo de una docena de lapiceros con la información: I. Por la compra de 10 docenas, obsequian 10 lapiceros. II. Tres docenas cuestan tantos soles como lapiceros dan por . III. Por compras superiores a  descuentan 5%. ¿Qué información es suficiente?', 'Datos Suficientes', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (246, NULL, 'En 2023, el número de días transcurridos del año excede en dos a los 3/8 del número de días que falta. El cumpleaños del director es el día siguiente. Determine la fecha.', 'Edades / Calendarios', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (247, NULL, 'En un reloj con marcas solo en 3, 6, 9 y 12, el horario está a la mitad entre las 3 y las 6. El ángulo entre horario y minutero es de 90°. ¿Qué hora marca el reloj aproximadamente?', 'Cronometría', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (248, NULL, 'Elmer tiene una terraza rectangular. Las regiones sombreadas representan una piscina circular y un huerto. ¿Cuál es el perímetro en metros de la región pavimentada?', 'Perímetros', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (249, NULL, 'Una servilleta rectangular se dobla para formar un triángulo (vértices superiores coinciden con el punto medio del lado AB de longitud L cm). ¿Cuál es el perímetro del triángulo en cm?', 'Triángulos', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (250, NULL, 'Dado un gráfico con preferencias: Ciencia ficción: 40, Acción: 35, Comedia: 45, Terror: 20, Musicales: 25. ¿Cuál es el porcentaje de estudiantes que prefieren acción o terror?', 'Porcentajes', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (251, NULL, 'Una caja contiene 8 esferas rojas, 12 blancas y 7 azules. ¿Qué cantidad mínima de extracciones se necesitan para sacar una esfera roja y 2 esferas azules?', 'Certezas', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (252, NULL, 'Dos enamorados distan 240m y van a su encuentro con velocidades de 2 m/s y 3 m/s. ¿Después de qué tiempo están separados 90m por primera vez?', 'Móviles', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (253, NULL, 'Suponga que en su familia solamente hay dos hermanos. ¿Qué relación tendrá con usted el hijo de la suegra de la mujer de su hermano?', 'Parentescos', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (254, NULL, 'Indique en qué cifra termina el número N = 2023^2023 - 1', 'Cifras Terminales', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (255, NULL, 'A, B, C, D, E y F se sientan en mesa circular con 8 sillas. F adyacente a dos asientos vacíos, D no junto a vacío, A junto a E y C. Se puede afirmar que B se sienta: I. Junto a D. II. Junto a un lugar vacío. III. Frente a E.', 'Orden de Información', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (256, NULL, 'De la figura dada, indique el número máximo de hexágonos que se pueden contar', 'Conteo de Figuras', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (257, NULL, 'Un terreno rectangular de 72m x 96m se desea cercar con árboles igualmente espaciados, con uno en cada esquina, y distancia máxima de 10m entre ellos. ¿Cuál es la menor cantidad de árboles necesarios?', 'MCD', NULL, 2, TRUE, NULL, 74, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (204, NULL, 'Con respecto al sistema nervioso, es correcto:', 'Sistema Nervioso', NULL, 2, TRUE, NULL, 89, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (165, NULL, 'Calcular el volumen de un prisma oblicuo ABC-A''B''C'' cuya área de la sección recta MNP es 6m² y sus aristas laterales miden AA''=2m, BB''=3m y CC''=4m', 'Tronco de Prisma', NULL, 2, TRUE, NULL, 76, NULL, 'aprobado', NULL);
INSERT INTO preguntas VALUES (61, NULL, 'Si las razones aritméticas de los términos de 1ra y 2da razón de una proporción geométrica son 8 y 32, respectivamente. Determine la relación entre la suma y diferencia de los consecuentes de dicha proporción.', 'Razones y Proporciones', NULL, 2, TRUE, NULL, 75, NULL, 'aprobado', NULL);
