CREATE TABLE areas (
  id SERIAL,
  bloque_id INTEGER,
  codigo VARCHAR(10),
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  orden INTEGER DEFAULT 0,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE asignaturas (
  id SERIAL,
  area_id INTEGER,
  codigo VARCHAR(20),
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  imagen_url VARCHAR(500),
  orden INTEGER DEFAULT 0,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE auditoria_accesos (
  id SERIAL,
  usuario_id uuid,
  evento VARCHAR(50) NOT NULL,
  ip_address inet,
  user_agent TEXT,
  detalles jsonb,
  fecha TIMESTAMP DEFAULT now()
);


CREATE TABLE bloques_tematicos (
  id SERIAL,
  codigo VARCHAR(10) NOT NULL,
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  orden INTEGER DEFAULT 0,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE codigos_otp (
  id SERIAL,
  usuario_id uuid NOT NULL,
  codigo_hash VARCHAR(255) NOT NULL,
  metodo VARCHAR(10),
  expira_en TIMESTAMP NOT NULL,
  usado BOOLEAN DEFAULT false,
  intentos_fallidos INTEGER DEFAULT 0
);


CREATE TABLE configuraciones (
  id SERIAL,
  clave VARCHAR(100) NOT NULL,
  valor TEXT,
  descripcion TEXT
);


CREATE TABLE configuraciones_puntaje (
  id SERIAL,
  grupo_academico_id INTEGER,
  asignatura_id INTEGER,
  numero_preguntas INTEGER DEFAULT 0,
  puntaje_pregunta numeric DEFAULT 0,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE cursos (
  id SERIAL,
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  orden INTEGER DEFAULT 0,
  imagen_url VARCHAR(500),
  activo BOOLEAN DEFAULT true
);


CREATE TABLE especialidades (
  id SERIAL,
  grupo_id INTEGER,
  nombre VARCHAR(100) NOT NULL,
  puntaje_minimo INTEGER DEFAULT 0,
  orden INTEGER DEFAULT 0,
  grupo_academico_id INTEGER,
  codigo VARCHAR(20)
);


CREATE TABLE flashcard_historial (
  id SERIAL,
  flashcard_id INTEGER NOT NULL,
  usuario_id uuid NOT NULL,
  calidad_respuesta INTEGER,
  tiempo_respuesta INTEGER DEFAULT 0,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE flashcards (
  id SERIAL,
  usuario_id uuid NOT NULL,
  pregunta_id INTEGER NOT NULL,
  estado VARCHAR(20) DEFAULT 'activa'::character varying,
  respondida BOOLEAN DEFAULT false,
  respondida_correcta BOOLEAN DEFAULT false,
  facilidad INTEGER DEFAULT 2500,
  intervalo INTEGER DEFAULT 1,
  repeticiones INTEGER DEFAULT 0,
  proxima_revision date DEFAULT CURRENT_DATE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE grupos_academicos (
  id SERIAL,
  codigo VARCHAR(20) NOT NULL,
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  orden INTEGER DEFAULT 0,
  activo BOOLEAN DEFAULT true,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE grupos_especialidad (
  id SERIAL,
  nombre VARCHAR(100) NOT NULL,
  descripcion TEXT,
  orden INTEGER DEFAULT 0
);


CREATE TABLE notificaciones (
  id SERIAL,
  usuario_id uuid NOT NULL,
  titulo VARCHAR(255),
  mensaje TEXT,
  leida BOOLEAN DEFAULT false,
  fecha_creacion TIMESTAMP DEFAULT now()
);


CREATE TABLE opciones (
  id SERIAL,
  pregunta_id INTEGER NOT NULL,
  texto TEXT NOT NULL,
  es_correcta BOOLEAN NOT NULL,
  activa BOOLEAN DEFAULT true
);


CREATE TABLE preguntas (
  id SERIAL,
  tema_id INTEGER,
  enunciado TEXT NOT NULL,
  explicacion TEXT,
  imagen_url VARCHAR(500),
  dificultad INTEGER DEFAULT 3,
  activa BOOLEAN DEFAULT true,
  tipo_id INTEGER,
  asignatura_id INTEGER,
  usuario_id INTEGER,
  estado VARCHAR(20) DEFAULT 'aprobado'::character varying,
  motivo_rechazo TEXT
);

